// Extract the response from Get Historical Rate node
const response = $input.all()[0].json;

// Determine if fallback was used
const usingFallback = response.fallback_used || false;

// Format the output for display
return [
  {
    json: {
      state: response.state,
      query_date: response.query_date,
      tax_rate: response.rate.tax_rate,
      tax_rate_percentage: (response.rate.tax_rate * 100).toFixed(2) + '%',
      stamping_fee: response.rate.stamping_fee,
      stamping_fee_percentage: response.rate.stamping_fee ? (response.rate.stamping_fee * 100).toFixed(3) + '%' : 'N/A',
      effective_from: response.rate.effective_from,
      effective_to: response.rate.effective_to || 'Current',
      legislative_source: response.rate.legislative_source,
      confidence: response.rate.confidence,
      fallback_status: usingFallback ? '⚠️ FALLBACK USED' : '✅ Historical Data Available',
      fallback_message: response.fallback_message || 'N/A',
      message: usingFallback 
        ? `Warning: Historical data unavailable for ${response.state} on ${response.query_date}. Current rate returned instead.`
        : `Successfully retrieved historical rate for ${response.state} on ${response.query_date}`
    }
  }
];
